import argparse
import json
import os

import torch
from torch.utils.data import Dataset, DataLoader
from torchvision import transforms

from model import build_model


class TensorImageDataset(Dataset):
    def __init__(self, pt_path, img_size=224, with_labels=False):
        obj = torch.load(pt_path, map_location='cpu')
        self.images = obj['images']
        self.labels = obj.get('labels', None)
        self.with_labels = with_labels and self.labels is not None
        self.transform = transforms.Compose([
            transforms.ToPILImage(),
            transforms.Resize((img_size, img_size), interpolation=transforms.InterpolationMode.BICUBIC),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
        ])

    def __len__(self):
        return self.images.shape[0]

    def __getitem__(self, idx):
        img = self.images[idx].permute(1, 2, 0).numpy()
        img = self.transform(img)
        if self.with_labels:
            return img, int(self.labels[idx])
        return img


def extract_state_and_meta(obj):
    if not isinstance(obj, dict):
        return obj, {}
    for key in ['model_state', 'model_state_dict', 'state_dict']:
        if key in obj and isinstance(obj[key], dict):
            return obj[key], obj
    if obj and all(torch.is_tensor(v) for v in obj.values()):
        return obj, {}
    raise ValueError(f'Unsupported checkpoint format with keys: {list(obj.keys())[:20]}')


def load_checkpoint(path, device):
    raw = torch.load(path, map_location='cpu')
    state, meta = extract_state_and_meta(raw)
    model_name = meta.get('model_name', 'convnext_tiny.fb_in22k_ft_in1k')
    num_classes = int(meta.get('num_classes', 100))
    img_size = int(meta.get('img_size', 224))
    dropout = float(meta.get('dropout', 0.0))
    infer_logit_tau = float(meta.get('infer_logit_tau', 0.0))

    model = build_model(model_name=model_name, num_classes=num_classes, pretrained=False, dropout=dropout)
    model.load_state_dict(state, strict=True)
    model.to(device)
    model.eval()
    return model, {
        'model_name': model_name,
        'num_classes': num_classes,
        'img_size': img_size,
        'infer_logit_tau': infer_logit_tau,
    }


def load_log_priors(data_path, num_classes):
    counts_path = os.path.join(data_path, 'class_counts.json')
    if not os.path.exists(counts_path):
        return None
    with open(counts_path, 'r') as f:
        raw = json.load(f)
    counts = torch.ones(num_classes, dtype=torch.float32)
    for k, v in raw.items():
        idx = int(k)
        if 0 <= idx < num_classes:
            counts[idx] = float(v)
    priors = (counts / counts.sum()).clamp_min(1e-12)
    return priors.log().view(1, -1)


@torch.no_grad()
def predict(model, loader, device, tau=0.0, log_priors=None):
    preds = []
    for batch in loader:
        if isinstance(batch, (list, tuple)):
            images = batch[0]
        else:
            images = batch
        images = images.to(device, non_blocking=True)
        logits = model(images)
        if log_priors is not None and abs(tau) > 1e-12:
            logits = logits + tau * log_priors.to(logits.device)
        preds.append(logits.argmax(dim=1).cpu())
    return torch.cat(preds, dim=0).tolist()


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--data_path', required=True)
    ap.add_argument('--checkpoint', required=True)
    ap.add_argument('--output', required=True)
    ap.add_argument('--batch_size', type=int, default=128)
    args = ap.parse_args()

    device = 'cuda' if torch.cuda.is_available() else 'cpu'
    model, meta = load_checkpoint(args.checkpoint, device)

    test_pt = os.path.join(args.data_path, 'test.pt')
    if not os.path.exists(test_pt):
        test_pt = os.path.join(args.data_path, 'val.pt')
    ds = TensorImageDataset(test_pt, img_size=meta['img_size'], with_labels=False)
    loader = DataLoader(ds, batch_size=args.batch_size, shuffle=False, num_workers=4, pin_memory=True)

    log_priors = load_log_priors(args.data_path, meta['num_classes'])
    preds = predict(model, loader, device, tau=meta['infer_logit_tau'], log_priors=log_priors)

    with open(args.output, 'w') as f:
        json.dump({'predictions': [int(x) for x in preds]}, f)


if __name__ == '__main__':
    main()
